{"action":"tool_call","tool_name":"write_file","arguments":{"path":"src/jsonl_tools.py","content":"import json
from json import JSONDecodeError


def dedupe_jsonl(blob: str, dedupe_key: str) -> str:
    """Return JSONL with duplicate objects removed by dedupe_key.

    For each duplicate key value, keep the first record and drop later records.
    Raise ValueError for malformed JSONL, non-object lines, or records missing
    dedupe_key.
    """
    seen = set()
    kept_lines = []

    for line_number, raw_line in enumerate(blob.splitlines(), start=1):
        if not raw_line.strip():
            continue
        try:
            record = json.loads(raw_line)
        except JSONDecodeError as exc:
            raise ValueError(f"invalid JSONL on line {line_number}") from exc

        if not isinstance(record, dict):
            raise ValueError(f"line {line_number} must be a JSON object")
        if dedupe_key not in record:
            raise ValueError(
                f"dedupe_key {dedupe_key!r} missing on line {line_number}"
            )

        key_value = record[dedupe_key]
        if key_value in seen:
            continue
        seen.add(key_value)
        kept_lines.append(raw_line)

    return "\n".join(kept_lines) + ("\n" if kept_lines else "")
"}}

